import { mkdirSync } from 'fs'
import { join, dirname } from 'path'
import { fileURLToPath } from 'url'

const __dirname = dirname(fileURLToPath(import.meta.url))

async function createZip() {
  const JSZip = (await import('jszip')).default
  const zip = new JSZip()
  const folder = zip.folder('systemmd-original-kit')

  folder.file('.cursorrules', `# SystemMD Original — .cursorrules
# Generated by hand. The file that started it all.

You are building a SaaS with Next.js 14, Supabase, Stripe and Resend.

## RULES
1. TypeScript strict mode. No any types.
2. All API keys server-side only. Never in client bundle.
3. Supabase RLS enabled on every table.
4. Every UI state handled: loading, error, empty, content.
5. Use clsx + tailwind-merge for className.
6. App Router only. No pages directory.
7. Server Components by default. Client Components only when needed.
8. Error boundaries on every major section.`)

  folder.file('schema.sql', `-- SystemMD Original Blueprint Kit
-- Database Schema

create table users (
  id uuid primary key references auth.users,
  email text not null,
  plan text default 'free',
  created_at timestamptz default now()
);

create table projects (
  id uuid primary key default gen_random_uuid(),
  user_id uuid references users(id) on delete cascade,
  name text not null,
  status text default 'active',
  created_at timestamptz default now()
);

alter table users enable row level security;
alter table projects enable row level security;

create policy "users_own" on users for all using (auth.uid() = id);
create policy "projects_own" on projects for all using (auth.uid() = user_id);`)

  folder.file('BUILD.md', `# SystemMD Original Blueprint Kit
# The file that started it all.
# systemmd.com

## WHAT THIS IS
A hand-crafted blueprint for building a production SaaS.
Before the AI generator, this was done by hand.

## STACK
- Frontend: Next.js 14 + TypeScript + Tailwind CSS
- Backend: Next.js API Routes
- Database: Supabase (PostgreSQL + RLS)
- Auth: Supabase Auth
- Payments: Stripe
- Email: Resend
- Hosting: Vercel

## BUILD GUIDE
1. Clone repo and install dependencies
2. Create Supabase project, run schema.sql
3. Copy .env.example to .env.local, fill all values
4. Run npm run dev
5. Deploy to Vercel

## THIS WEEK
1. Set up Supabase project and run schema
2. Implement auth flow (signup, login, callback)
3. Build dashboard layout with sidebar
4. Create first core feature
5. Add Stripe checkout for first paid plan`)

  folder.file('.env.example', `# Supabase
NEXT_PUBLIC_SUPABASE_URL=
NEXT_PUBLIC_SUPABASE_ANON_KEY=
SUPABASE_SERVICE_ROLE_KEY=

# Stripe
STRIPE_SECRET_KEY=
NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY=
STRIPE_WEBHOOK_SECRET=

# Resend
RESEND_API_KEY=

# App
NEXT_PUBLIC_APP_URL=http://localhost:3000`)

  folder.file('README.md', `# SystemMD Original Blueprint Kit

The hand-crafted blueprint that started SystemMD.

## Files
- .cursorrules — AI coding rules for Cursor/Windsurf
- schema.sql — Supabase database schema
- BUILD.md — Full build guide
- .env.example — Environment variables

## Quick Start
npx create-next-app@latest my-app --typescript --tailwind --eslint --app --src-dir
cd my-app
# Run schema.sql in Supabase SQL Editor
# Copy .env.example to .env.local

---
systemmd.com`)

  const outputPath = join(__dirname, '..', 'public', 'systemmd-original-kit.zip')
  mkdirSync(join(__dirname, '..', 'public'), { recursive: true })

  const buffer = await zip.generateAsync({ type: 'nodebuffer', compression: 'DEFLATE', compressionOptions: { level: 6 } })

  const { writeFileSync } = await import('fs')
  writeFileSync(outputPath, buffer)
  console.log('✓ Created public/systemmd-original-kit.zip')
}

createZip().catch(console.error)
